@router.delete("/expenses/{id}")
def delete_expense(id: str):
    expenses = load_expenses()

    # ID로 항목 찾기
    found = False
    filtered = []
    for exp in expenses:
        if exp.get("id") == id:
            found = True
        else:
            filtered.append(exp)

    if not found:
        raise HTTPException(404, "지출 항목을 찾을 수 없습니다")

    # 삭제된 목록 저장
    save_expenses(filtered)

    return {"message": "삭제되었습니다", "id": id}

